using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private ITransformer? _model;
    private PredictionEngine<TicketInput, TicketPrediction>? _predictionEngine;
    private MulticlassClassificationMetrics? _metrics;
    private string[] _categoryLabels = [];

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    }

    public MulticlassClassificationMetrics TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Use cross-validation for evaluation since the dataset is small
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);
        _metrics = cvResults.OrderByDescending(r => r.Metrics.MicroAccuracy).First().Metrics;

        // Train final model on full dataset
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(_model);

        // Extract category labels from the model's key-to-value mapping
        var transformedData = _model.Transform(dataView);
        var labelColumn = transformedData.Schema["PredictedLabel"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        transformedData.Schema["Score"].GetSlotNames(ref slotNames);
        _categoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        return _metrics;
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        if (_predictionEngine is null)
            throw new InvalidOperationException("Model has not been trained yet.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationMetricsResponse GetMetrics()
    {
        if (_metrics is null)
            throw new InvalidOperationException("Model has not been evaluated yet.");

        return new EvaluationMetricsResponse
        {
            MicroAccuracy = _metrics.MicroAccuracy,
            MacroAccuracy = _metrics.MacroAccuracy,
            LogLoss = _metrics.LogLoss,
            LogLossReduction = _metrics.LogLossReduction
        };
    }
}

